package ReorganizeString;

// 767

class ReorganizeString {
   public static void main(String[] args) {
      Solution s = new Solution();
      System.out.println(s.reorganizeString("aaabc"));
      System.out.println(s.reorganizeString("abcddd"));
      System.out.println(s.reorganizeString("aab"));
      System.out.println(s.reorganizeString("aaab")); // none
      System.out.println(s.reorganizeString("aaabb"));
      System.out.println(s.reorganizeString("lkllgpllgqlywlllptl")); // TLE
      System.out.println(s.reorganizeString("")); // TLE
      System.out.println(s.reorganizeString(""));
   }
}